from agent import *from models.products import *def run(context, session):    session.queue(Request('http://www.wheelsforwomen.ie/index.php/category/car-seat-review/'), process_revlist, dict(cat='Car Seat Review'))def process_revlist(data, context, session):    revs = data.xpath("//div[@class='et-description']/h2/a")    for rev in revs:        title = rev.xpath(".//text()").string()        url = rev.xpath("@href").string()        session.queue(Request(url), process_product, dict(context, title=title, url=url))    next_url = data.xpath("//link[@rel='next']/@href").string()    if next_url:        session.queue(Request(next_url), process_revlist, dict(context))def process_product(data, context, session):    product = Product()    product.url = context['url']    product.ssid = context['url'].split('/')[-2]    product.category = context['cat']    name = context['title']    if name and "Review: " in name:        name = name.split("Review: ")[-1]    else:        return  # Not a review    product.name = name    review = Review()    review.title = context['title']    review.url = product.url    review.ssid = product.ssid    review.type = 'pro'    date = data.xpath("//meta[@property='article:published_time']/@content").string()    if date:        review.date = date.split('T')[0]    author = data.xpath('//meta[@name="author"]/@content').string()    if author:        review.authors.append(Person(name=author, ssid=author))    pros = data.xpath('//p[strong[contains(., "Why you’ll want one")]]/text()').string(multiple=True)    if pros:        review.properties.append(ReviewProperty(type='pros', value=pros))    cons = data.xpath('//p[strong[contains(., "Why you won’t")]]/text()').string()    if cons:        review.properties.append(ReviewProperty(type='cons', value=cons))    grade_overall = data.xpath('//p[strong[contains(., "Star Rating")]]/text()[contains(., "* (")]').string()    if grade_overall:        value = grade_overall.split('*')[0].split(':')[-1]        if value:            review.grades.append(Grade(type='overall', value=float(value), best=5.0))    summary = data.xpath('//meta[@property="og:description"]/@content').string()    if summary and not '[…]' in summary:        review.properties.append(ReviewProperty(type='summary', value=summary))    excerpt = data.xpath('//p[position() > 1 and position() < last()][not(contains(., "Where can I buy one"))][not(contains(., "Why you’ll want one"))][not(strong[contains(., "Why you won’t")])][following-sibling::p[strong[contains(., "Seat:")]]]//text()').string(multiple=True)    if not excerpt:        excerpt = data.xpath('//div[@id="left-area"]/p[not(contains(@class, "comment"))][not(strong[text()="{}"])]//text()').string(multiple=True).format(author)    if excerpt:        if summary:            excerpt = excerpt.replace(summary, '')        review.add_property(type='excerpt', value=excerpt)        product.reviews.append(review)        session.emit(product)